-- {"operators": "INNER_JOIN,ORDER,WINDOW", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "DISTRICT,CUSTOMER", "ducklake": true}
SELECT c.C_W_ID, d.D_NAME, c.C_ID, c.C_BALANCE, DENSE_RANK() OVER (PARTITION BY c.C_W_ID ORDER BY c.C_BALANCE DESC) AS bal_rank FROM CUSTOMER c JOIN DISTRICT d ON c.C_W_ID = d.D_W_ID AND c.C_D_ID = d.D_ID;
